import React, { useState } from 'react';
import image from '../../../images/quizImages/2.svg';
import InputField from '../InputField';
import Buttons from '../Buttons';
import ProgressBar from '../ProgressBar';
import './screentwo.css';

const ScreenTwo = () => {

  return (
    <div id="screen2" className="screen">
      <h1 className="title">First we are going to need some of your personal information</h1>
      <p className="message">Don’t worry everything will be kept anonymous and it is in safe hands!</p>
      <div className="contact-details">
        <InputField
          className="name"
          type="text"
          name="Name"
          placeHolderMessage="ex. Manuel Aguires"
        />
        <InputField
          className="mail"
          type="text"
          name="Mail"
          placeHolderMessage="ex. youremail@gmail.com"
        />
        <InputField
          className="phone-number"
          type="tel"
          name="PhoneNumber"
          value={formData.phone}
          placeHolderMessage="ex. +(34) 6548752146"
        />
        <InputField
          className="gender"
          type="text"
          name="Gender"
          placeHolderMessage="Male / Female"
        />
      </div>
      <div className="graph">
        <img src={image} alt="image" />
      </div>
    </div>
  );
};

export default ScreenTwo;
